import socket, threading, os, time, sys
HOST,PORT='127.0.0.1',4555
# wait for qemu serial server
for _ in range(60):
    try:
        s=socket.create_connection((HOST,PORT),timeout=2); break
    except OSError: time.sleep(1)
else:
    sys.exit("cannot connect")
s.setblocking(True)
log=open('/app/con.log','ab',buffering=0)
def reader():
    while True:
        try:
            d=s.recv(4096)
        except OSError: break
        if not d: break
        log.write(d)
threading.Thread(target=reader,daemon=True).start()
# named pipe for input
if not os.path.exists('/app/in.pipe'): os.mkfifo('/app/in.pipe')
while True:
    with open('/app/in.pipe','rb') as p:
        while True:
            d=p.read(4096)
            if not d: break
            s.sendall(d)
PY
